namespace ShipmentTracker.Shared;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerEmail { get; set; }
    public string? Notes { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Data;
using ShipmentTracker.Shared;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            return Results.Ok(await db.Shipments.OrderByDescending(s => s.CreatedAt).ToListAsync());
        });

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        group.MapPost("/", async (Shipment shipment, ApplicationDbContext db) =>
        {
            shipment.CreatedAt = DateTime.UtcNow;
            if (string.IsNullOrEmpty(shipment.TrackingNumber))
            {
                shipment.TrackingNumber = $"TRK-{Guid.NewGuid().ToString()[..8].ToUpper()}";
            }
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/track/{shipment.TrackingNumber}", shipment);
        });

        group.MapPut("/{id}", async (int id, Shipment updated, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = updated.Status;
            shipment.Origin = updated.Origin;
            shipment.Destination = updated.Destination;
            shipment.EstimatedDelivery = updated.EstimatedDelivery;
            shipment.CustomerEmail = updated.CustomerEmail;
            shipment.Notes = updated.Notes;

            await db.SaveChangesAsync();
            return Results.Ok(shipment);
        });
    }
}

