@page "/dispatcher"
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h3>Dispatcher Dashboard</h3>

@if (shipments == null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="mb-3">
        <label class="form-label">Filter by Status:</label>
        <select class="form-select w-auto d-inline-block" @bind="statusFilter">
            <option value="">All</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
        <button class="btn btn-primary ms-3" @onclick="ToggleNewForm">+ New Shipment</button>
    </div>

    @if (showNewForm)
    {
        <div class="card mb-3 p-3">
            <h5>Create New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-3">
                    <button class="btn btn-success" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary ms-1" @onclick="ToggleNewForm">Cancel</button>
                </div>
            </div>
        </div>
    }

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm w-auto d-inline-block"
                                value="@shipment.Status"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private string statusFilter = "";
    private bool showNewForm;
    private Shipment newShipment = new();

    private IEnumerable<Shipment> FilteredShipments =>
        string.IsNullOrEmpty(statusFilter)
            ? shipments!
            : shipments!.Where(s => s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            shipments = await Http.GetFromJsonAsync<List<Shipment>>("/api/shipments");
        }
        catch
        {
            shipments = new();
        }
    }

    private void ToggleNewForm()
    {
        showNewForm = !showNewForm;
        newShipment = new();
    }

    private async Task CreateShipment()
    {
        var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            showNewForm = false;
            newShipment = new();
            await LoadShipments();
        }
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            shipment.Status = newStatus;
            await Http.PutAsJsonAsync($"/api/shipments/{shipment.Id}", shipment);
            await LoadShipments();
        }
    }

    private string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "info",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Delayed => "danger",
        _ => "secondary"
    };
}

@page "/track"
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject HttpClient Http

<PageTitle>Track Shipment</PageTitle>

<h3>Track Your Shipment</h3>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
