@code {
    private string trackingNumber = "";
    private Shipment? shipment;
    private bool isLoading;
    private string? errorMessage;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        errorMessage = null;
        shipment = null;

        try
        {
            var response = await Http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
            if (response.IsSuccessStatusCode)
            {
                shipment = await response.Content.ReadFromJsonAsync<Shipment>();
            }
            else
            {
                errorMessage = "Shipment not found. Please check the tracking number and try again.";
            }
        }
        catch
        {
            errorMessage = "Unable to retrieve shipment information. Please try again later.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await TrackShipment();
        }
    }

    private int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        _ => 0
    };

    private string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "info",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Delayed => "danger",
        _ => "secondary"
    };

    private string StepClass(ShipmentStatus step, ShipmentStatus current)
    {
        if (current == ShipmentStatus.Delayed)
            return step <= ShipmentStatus.InTransit ? "fw-bold text-danger" : "";
        return step <= current ? "fw-bold text-success" : "";
    }
}

